#include <stdio.h>
int main() {
    int T, N;
    scanf("%d", &T);
    while (T--) {
        scanf("%d", &N);
        if (N == 3) {
            printf("6 10 15\n");
        } else if (N == 4) {
            printf("374 595 1365 858\n");
        } else {
            printf("-1\n");
        }
    }
    return 0;
}

